import React, { useState, useMemo } from 'react';
import { PurchaseOrder, OverallPOStatus, FulfillmentStatus, OrderStatus, POItemStatus } from '../types';
import { exportToCSV } from '../utils/export';
import { ArrowDownTrayIcon, ClipboardDocumentListIcon, ExclamationTriangleIcon, TruckIcon, CheckCircleIcon, DatabaseIcon } from './icons';

interface ReportsPaneProps {
    purchaseOrders: PurchaseOrder[];
    onUpdatePO: (po: PurchaseOrder) => void;
}

type TabType = 'general' | 'missingOA' | 'dispatchPending' | 'oaFilled' | 'allocation';

const ReportsPane: React.FC<ReportsPaneProps> = ({ purchaseOrders, onUpdatePO }) => {
    const [activeTab, setActiveTab] = useState<TabType>('general');

    // General Tab State
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [statusFilter, setStatusFilter] = useState('');

    // General Filter Logic
    const filteredGeneralPOs = useMemo(() => {
        return purchaseOrders.filter(po => {
            if (startDate && new Date(po.poDate) < new Date(startDate)) return false;
            if (endDate && new Date(po.poDate) > new Date(endDate)) return false;
            if (statusFilter && po.status !== statusFilter) return false;
            return true;
        });
    }, [purchaseOrders, startDate, endDate, statusFilter]);

    // Missing OA Logic
    const missingOAData = useMemo(() => {
        const results: { po: PurchaseOrder, items: any[] }[] = [];
        purchaseOrders.forEach(po => {
            if (po.fulfillmentStatus === FulfillmentStatus.Partial || po.fulfillmentStatus === FulfillmentStatus.NotAvailable) {
                const missingItems = po.items.filter(item => {
                    const isUnavailable = item.status === POItemStatus.NotAvailable || item.stockStatus === 'Unavailable';
                    return isUnavailable && (!item.oaNo || !item.oaDate);
                });
                if (missingItems.length > 0) results.push({ po, items: missingItems });
            }
        });
        return results;
    }, [purchaseOrders]);

    // OA Filled Logic
    const oaFilledData = useMemo(() => {
        const results: { po: PurchaseOrder, items: any[] }[] = [];
        purchaseOrders.forEach(po => {
            const filledItems = po.items.filter(item => item.oaNo && item.oaDate);
            if (filledItems.length > 0) {
                results.push({ po, items: filledItems });
            }
        });
        return results;
    }, [purchaseOrders]);

    // Allocation Logic (New Report)
    const allocationData = useMemo(() => {
        const results: { po: PurchaseOrder, item: any }[] = [];
        purchaseOrders.forEach(po => {
            (po.items || []).forEach(item => {
                if ((item.allocatedQuantity || 0) > 0) {
                    results.push({ po, item });
                }
            });
        });
        return results;
    }, [purchaseOrders]);

    // Dispatch Pending Logic (Fully Available but Not Shipped)
    const dispatchPendingPOs = useMemo(() => {
        return purchaseOrders.filter(po => {
            const isFullyAvailable = po.fulfillmentStatus === FulfillmentStatus.Fulfillment;
            const isNotShipped = po.orderStatus !== OrderStatus.ShippedInSystemDC && po.orderStatus !== OrderStatus.Invoiced;
            return isFullyAvailable && isNotShipped;
        });
    }, [purchaseOrders]);

    // Local state for remarks editing in Dispatch Pending tab
    const [remarksEdits, setRemarksEdits] = useState<Record<string, string>>({});

    const handleRemarkChange = (poId: string, val: string) => {
        setRemarksEdits(prev => ({ ...prev, [poId]: val }));
    };

    const handleSaveRemark = (po: PurchaseOrder) => {
        const newRemark = remarksEdits[po.id];
        if (newRemark !== undefined) {
            onUpdatePO({ ...po, dispatchRemarks: newRemark });
            alert('Remark saved successfully.');
        }
    };

    const exportOAFilled = () => {
        const rows: any[] = [];
        oaFilledData.forEach(({ po, items }) => {
            items.forEach(item => {
                rows.push({
                    'PO Number': po.poNumber,
                    'Date': po.poDate,
                    'Customer': po.customerName,
                    'Part Number': item.partNumber,
                    'OA No': item.oaNo,
                    'OA Date': item.oaDate,
                    'Item Status': item.status
                });
            });
        });
        if (rows.length === 0) return alert("No data to export");
        const headers = Object.keys(rows[0]).join(',');
        const csvRows = rows.map(row => Object.values(row).map(v => `"${v}"`).join(',')).join('\n');
        const csvContent = `${headers}\n${csvRows}`;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = 'oa_numbers_filled_report.csv';
        link.click();
    };

    const exportMissingOA = () => {
        const rows: any[] = [];
        missingOAData.forEach(({ po, items }) => {
            items.forEach(item => {
                rows.push({
                    'PO Number': po.poNumber,
                    'Date': po.poDate,
                    'Customer': po.customerName,
                    'Part Number': item.partNumber,
                    'Qty': item.quantity,
                    'Item Status': item.status,
                    'OA No': item.oaNo || 'MISSING',
                    'OA Date': item.oaDate || 'MISSING'
                });
            });
        });
        if (rows.length === 0) return alert("No data to export");
        const headers = Object.keys(rows[0]).join(',');
        const csvRows = rows.map(row => Object.values(row).map(v => `"${v}"`).join(',')).join('\n');
        const csvContent = `${headers}\n${csvRows}`;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = 'missing_oa_report.csv';
        link.click();
    };

    const exportAllocationReport = () => {
        const rows = allocationData.map(({ po, item }) => ({
            'PO Number': po.poNumber,
            'Customer': po.customerName,
            'Part Number': item.partNumber,
            'Allocated Qty': item.allocatedQuantity,
            'Total Required': item.quantity,
            'Item Status': item.status,
            'Branch': po.mainBranch || 'N/A'
        }));
        if (rows.length === 0) return alert("No allocation data found");
        const headers = Object.keys(rows[0]).join(',');
        const csvRows = rows.map(row => Object.values(row).map(v => `"${v}"`).join(',')).join('\n');
        const csvContent = `${headers}\n${csvRows}`;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = 'stock_allocation_report.csv';
        link.click();
    };

    const exportDispatchPending = () => {
        const rows = dispatchPendingPOs.map(po => ({
            'PO Number': po.poNumber,
            'Date': po.poDate,
            'Customer': po.customerName,
            'Branch': po.mainBranch,
            'Value': po.items.reduce((acc, i) => acc + (i.quantity * i.rate), 0),
            'Dispatch Remarks': remarksEdits[po.id] !== undefined ? remarksEdits[po.id] : (po.dispatchRemarks || '')
        }));
        if (rows.length === 0) return alert("No data to export");
        const headers = Object.keys(rows[0]).join(',');
        const csvRows = rows.map(row => Object.values(row).map(v => `"${v}"`).join(',')).join('\n');
        const csvContent = `${headers}\n${csvRows}`;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = 'dispatch_pending_report.csv';
        link.click();
    };

    return (
        <div className="container mx-auto p-4 sm:p-6 lg:p-8 h-full flex flex-col">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-slate-200 dark:border-slate-700 p-6 flex-1 flex flex-col">
                <div className="flex items-center gap-3 mb-6 pb-4 border-b dark:border-slate-700">
                    <ClipboardDocumentListIcon className="w-8 h-8 text-red-600" />
                    <div>
                        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Reports Center</h2>
                        <p className="text-slate-500 dark:text-slate-400">Generate, view, and export detailed reports.</p>
                    </div>
                </div>

                {/* Tabs */}
                <div className="flex flex-wrap space-x-1 rounded-xl bg-slate-100 dark:bg-slate-900/50 p-1 mb-6">
                    <button
                        onClick={() => setActiveTab('general')}
                        className={`flex-1 rounded-lg py-2.5 text-sm font-medium leading-5 transition-all ${
                            activeTab === 'general'
                                ? 'bg-white dark:bg-slate-700 shadow text-red-700 dark:text-red-400'
                                : 'text-slate-500 hover:bg-white/[0.12] hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        General Data Export
                    </button>
                    <button
                        onClick={() => setActiveTab('allocation')}
                        className={`flex-1 rounded-lg py-2.5 text-sm font-medium leading-5 transition-all flex justify-center items-center gap-2 ${
                            activeTab === 'allocation'
                                ? 'bg-white dark:bg-slate-700 shadow text-indigo-600 dark:text-indigo-400'
                                : 'text-slate-500 hover:bg-white/[0.12] hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        <DatabaseIcon className="w-4 h-4" /> Allocation Report
                    </button>
                    <button
                        onClick={() => setActiveTab('oaFilled')}
                        className={`flex-1 rounded-lg py-2.5 text-sm font-medium leading-5 transition-all flex justify-center items-center gap-2 ${
                            activeTab === 'oaFilled'
                                ? 'bg-white dark:bg-slate-700 shadow text-green-600 dark:text-green-400'
                                : 'text-slate-500 hover:bg-white/[0.12] hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        <CheckCircleIcon className="w-4 h-4" /> OA Numbers Filled
                    </button>
                    <button
                        onClick={() => setActiveTab('missingOA')}
                        className={`flex-1 rounded-lg py-2.5 text-sm font-medium leading-5 transition-all flex justify-center items-center gap-2 ${
                            activeTab === 'missingOA'
                                ? 'bg-white dark:bg-slate-700 shadow text-amber-600 dark:text-amber-400'
                                : 'text-slate-500 hover:bg-white/[0.12] hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        <ExclamationTriangleIcon className="w-4 h-4" /> Missing OA Report
                    </button>
                    <button
                        onClick={() => setActiveTab('dispatchPending')}
                        className={`flex-1 rounded-lg py-2.5 text-sm font-medium leading-5 transition-all flex justify-center items-center gap-2 ${
                            activeTab === 'dispatchPending'
                                ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400'
                                : 'text-slate-500 hover:bg-white/[0.12] hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        <TruckIcon className="w-4 h-4" /> Ready to Ship
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-auto">
                    {activeTab === 'general' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg">
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Start Date</label>
                                    <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">End Date</label>
                                    <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Status</label>
                                    <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none">
                                        <option value="">All Statuses</option>
                                        {Object.values(OverallPOStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                    </select>
                                </div>
                            </div>
                            <div className="flex items-center justify-between">
                                <p className="text-slate-600 dark:text-slate-400">Total Matching Records: <span className="font-bold text-slate-800 dark:text-white">{filteredGeneralPOs.length}</span></p>
                                <button onClick={() => exportToCSV(filteredGeneralPOs)} className="flex items-center gap-2 px-6 py-3 text-white bg-red-600 rounded-lg hover:bg-red-700 shadow-md">
                                    <ArrowDownTrayIcon className="w-5 h-5" /> Export Filtered Data
                                </button>
                            </div>
                        </div>
                    )}

                    {activeTab === 'allocation' && (
                        <div className="space-y-4 h-full flex flex-col">
                            <div className="flex justify-between items-center mb-2">
                                <p className="text-slate-600 dark:text-slate-400">System-wide record of stock quantities assigned to specific Purchase Orders.</p>
                                <button onClick={exportAllocationReport} className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-indigo-700 bg-indigo-100 hover:bg-indigo-200 rounded-lg">
                                    <ArrowDownTrayIcon className="w-4 h-4" /> Export Allocation Report
                                </button>
                            </div>
                            <div className="flex-1 overflow-auto rounded-lg border border-slate-200 dark:border-slate-700">
                                <table className="w-full text-left text-sm text-slate-600 dark:text-slate-400">
                                    <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase sticky top-0">
                                        <tr>
                                            <th className="p-3">PO Number</th>
                                            <th className="p-3">Customer</th>
                                            <th className="p-3">Part Number</th>
                                            <th className="p-3 text-right">Allocated</th>
                                            <th className="p-3 text-right">Required</th>
                                            <th className="p-3">Progress</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                                        {allocationData.length > 0 ? (
                                            allocationData.map(({ po, item }, idx) => {
                                                const percent = Math.min(100, Math.round((item.allocatedQuantity / item.quantity) * 100));
                                                return (
                                                    <tr key={`${po.id}-${idx}`} className="bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                                        <td className="p-3 font-medium text-slate-900 dark:text-white">{po.poNumber}</td>
                                                        <td className="p-3">{po.customerName}</td>
                                                        <td className="p-3 font-bold">{item.partNumber}</td>
                                                        <td className="p-3 text-right font-black text-indigo-600">{item.allocatedQuantity}</td>
                                                        <td className="p-3 text-right">{item.quantity}</td>
                                                        <td className="p-3">
                                                            <div className="w-full bg-slate-200 dark:bg-slate-700 rounded-full h-2.5 max-w-[100px]">
                                                                <div className="bg-indigo-600 h-2.5 rounded-full" style={{ width: `${percent}%` }}></div>
                                                            </div>
                                                            <span className="text-[10px] text-slate-500">{percent}%</span>
                                                        </td>
                                                    </tr>
                                                );
                                            })
                                        ) : (
                                            <tr><td colSpan={6} className="p-8 text-center text-slate-500">No stock allocations have been made yet.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {activeTab === 'oaFilled' && (
                        <div className="space-y-4 h-full flex flex-col">
                            <div className="flex justify-between items-center mb-2">
                                <p className="text-slate-600 dark:text-slate-400">Total OA Entries: <span className="font-bold text-green-600">{oaFilledData.reduce((acc, d) => acc + d.items.length, 0)}</span> items across <span className="font-bold">{oaFilledData.length}</span> POs.</p>
                                <button onClick={exportOAFilled} className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-green-700 bg-green-100 hover:bg-green-200 rounded-lg">
                                    <ArrowDownTrayIcon className="w-4 h-4" /> Export OA Report
                                </button>
                            </div>
                            <div className="flex-1 overflow-auto rounded-lg border border-slate-200 dark:border-slate-700">
                                <table className="w-full text-left text-sm text-slate-600 dark:text-slate-400">
                                    <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase sticky top-0">
                                        <tr>
                                            <th className="p-3">PO Number</th>
                                            <th className="p-3">Customer</th>
                                            <th className="p-3">Part Number</th>
                                            <th className="p-3">OA Number</th>
                                            <th className="p-3">OA Date</th>
                                            <th className="p-3">Status</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                                        {oaFilledData.length > 0 ? (
                                            oaFilledData.map(({ po, items }) => (
                                                <React.Fragment key={po.id}>
                                                    {items.map((item, idx) => (
                                                        <tr key={`${po.id}-${idx}`} className="bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                                            <td className="p-3 font-medium">{po.poNumber}</td>
                                                            <td className="p-3">{po.customerName}</td>
                                                            <td className="p-3">{item.partNumber}</td>
                                                            <td className="p-3 font-bold text-green-600">{item.oaNo}</td>
                                                            <td className="p-3">{item.oaDate}</td>
                                                            <td className="p-3">{item.status}</td>
                                                        </tr>
                                                    ))}
                                                </React.Fragment>
                                            ))
                                        ) : (
                                            <tr><td colSpan={6} className="p-8 text-center text-slate-500">No OA numbers have been recorded yet.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {activeTab === 'missingOA' && (
                        <div className="space-y-4 h-full flex flex-col">
                            <div className="flex justify-between items-center mb-2">
                                <p className="text-slate-600 dark:text-slate-400">Missing OA details for unavailable items in pending POs.</p>
                                <button onClick={exportMissingOA} className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-amber-700 bg-amber-100 hover:bg-amber-200 rounded-lg">
                                    <ArrowDownTrayIcon className="w-4 h-4" /> Export Report
                                </button>
                            </div>
                            <div className="flex-1 overflow-auto rounded-lg border border-slate-200 dark:border-slate-700">
                                <table className="w-full text-left text-sm text-slate-600 dark:text-slate-400">
                                    <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase sticky top-0">
                                        <tr>
                                            <th className="p-3">PO Number</th>
                                            <th className="p-3">Customer</th>
                                            <th className="p-3">Part Number</th>
                                            <th className="p-3">Qty</th>
                                            <th className="p-3 text-red-600 font-bold">Missing Details</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                                        {missingOAData.length > 0 ? (
                                            missingOAData.map(({ po, items }) => (
                                                <React.Fragment key={po.id}>
                                                    {items.map((item, idx) => (
                                                        <tr key={`${po.id}-${idx}`} className="bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                                            <td className="p-3 font-medium">{po.poNumber}</td>
                                                            <td className="p-3">{po.customerName}</td>
                                                            <td className="p-3">{item.partNumber}</td>
                                                            <td className="p-3">{item.quantity}</td>
                                                            <td className="p-3 font-bold text-red-500">{!item.oaNo && "OA No. "}{!item.oaNo && !item.oaDate && "& "}{!item.oaDate && "OA Date"}</td>
                                                        </tr>
                                                    ))}
                                                </React.Fragment>
                                            ))
                                        ) : (
                                            <tr><td colSpan={5} className="p-8 text-center text-slate-500">No missing OA data found.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {activeTab === 'dispatchPending' && (
                        <div className="space-y-4 h-full flex flex-col">
                             <div className="flex justify-between items-center mb-2">
                                <p className="text-slate-600 dark:text-slate-400">Orders Fully Available but not yet shipped.</p>
                                <button onClick={exportDispatchPending} className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-blue-700 bg-blue-100 hover:bg-blue-200 rounded-lg">
                                    <ArrowDownTrayIcon className="w-4 h-4" /> Export Report
                                </button>
                            </div>
                             <div className="flex-1 overflow-auto rounded-lg border border-slate-200 dark:border-slate-700">
                                <table className="w-full text-left text-sm text-slate-600 dark:text-slate-400">
                                    <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase sticky top-0">
                                        <tr>
                                            <th className="p-3">PO Number</th>
                                            <th className="p-3">Customer</th>
                                            <th className="p-3">Value</th>
                                            <th className="p-3">Dispatch Remarks</th>
                                            <th className="p-3 text-center">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                                        {dispatchPendingPOs.length > 0 ? (
                                            dispatchPendingPOs.map(po => (
                                                <tr key={po.id} className="bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                                    <td className="p-3 font-medium">{po.poNumber}</td>
                                                    <td className="p-3">{po.customerName}</td>
                                                    <td className="p-3">{po.items.reduce((acc, i) => acc + (i.quantity * i.rate), 0).toLocaleString('en-IN', { style: 'currency', currency: 'INR' })}</td>
                                                    <td className="p-3"><textarea className="w-full p-2 text-sm border border-slate-300 rounded dark:bg-slate-900 dark:border-slate-600" rows={2} value={remarksEdits[po.id] !== undefined ? remarksEdits[po.id] : (po.dispatchRemarks || '')} onChange={(e) => handleRemarkChange(po.id, e.target.value)} /></td>
                                                    <td className="p-3 text-center"><button onClick={() => handleSaveRemark(po)} className="px-3 py-1.5 bg-blue-600 text-white text-xs font-bold rounded hover:bg-blue-700">Save</button></td>
                                                </tr>
                                            ))
                                        ) : (
                                            <tr><td colSpan={5} className="p-8 text-center text-slate-500">No pending dispatches.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default ReportsPane;

import React, { useState, useMemo } from 'react';
import type { StockItem, PurchaseOrder, StockMovement, POItem } from '../types';
import { ArrowUpTrayIcon, TruckIcon, XMarkIcon, MagnifyingGlassIcon, ArrowDownTrayIcon, PlusIcon, CurrencyRupeeIcon, ClockIcon, ClipboardDocumentListIcon } from './icons';
import { downloadStockTemplate } from '../utils/export';

interface StockManagementPaneProps {
  stock: StockItem[];
  purchaseOrders: PurchaseOrder[];
  movements: StockMovement[];
  onInward: (partNumber: string, qty: number, remark: string) => Promise<void>;
  onWalkingSale: (partNumber: string, qty: number, remark: string) => Promise<void>;
  onAllocate: (poId: string, partNumber: string, qty: number) => Promise<void>;
  onRegisterPart: (partNumber: string, description: string, initialQty: number) => Promise<void>;
  onBulkStockUpload: (items: { partNumber: string; description: string; quantity: number }[]) => Promise<void>;
  onNavigateToReports?: () => void;
}

const StockManagementPane: React.FC<StockManagementPaneProps> = ({ 
    stock, purchaseOrders, movements, onInward, onWalkingSale, onAllocate, onRegisterPart, onBulkStockUpload, onNavigateToReports 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeModal, setActiveModal] = useState<'inward' | 'walking' | 'allocate' | 'history' | 'registerPart' | null>(null);
  const [selectedPart, setSelectedPart] = useState<string | null>(null);

  // Search filter for PO allocation
  const [poSearchQuery, setPoSearchQuery] = useState('');
  const [formState, setFormState] = useState({ qty: 1, remark: '', poId: '', partNumber: '', description: '' });

  const filteredStock = useMemo(() => {
    return stock.filter(s => 
        (s.partNumber || '').toLowerCase().includes(searchTerm.toLowerCase()) || 
        (s.description || '').toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stock, searchTerm]);

  const partHistory = useMemo(() => {
    if (!selectedPart) return [];
    return movements.filter(m => m.partNumber === selectedPart);
  }, [movements, selectedPart]);

  // Filters POs that need this part and matches the search query
  const targetPOsForPart = useMemo(() => {
    if (!selectedPart) return [];
    const normalizedPart = selectedPart.trim().toLowerCase();

    return purchaseOrders.filter(po => {
        const matchingItem = po.items.find(item => (item.partNumber || '').trim().toLowerCase() === normalizedPart);
        const needsAllocation = matchingItem ? (Number(matchingItem.quantity || 0) - Number(matchingItem.allocatedQuantity || 0)) > 0 : false;

        const matchesSearch = (po.poNumber || '').toLowerCase().includes(poSearchQuery.toLowerCase()) || 
                             (po.customerName || '').toLowerCase().includes(poSearchQuery.toLowerCase());

        return needsAllocation && matchesSearch;
    });
  }, [purchaseOrders, selectedPart, poSearchQuery]);

  const handlePOSelectionChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const poId = e.target.value;
    if (!poId) {
        setFormState(prev => ({ ...prev, poId: '', qty: 1 }));
        return;
    }

    const selectedPO = targetPOsForPart.find(p => p.id === poId);
    if (selectedPO && selectedPart) {
        const normalizedPart = selectedPart.trim().toLowerCase();
        const item = selectedPO.items.find(i => (i.partNumber || '').trim().toLowerCase() === normalizedPart);
        const neededQty = item ? (Number(item.quantity || 0) - Number(item.allocatedQuantity || 0)) : 1;

        setFormState(prev => ({ 
            ...prev, 
            poId, 
            qty: Math.max(1, neededQty) 
        }));
    } else {
        setFormState(prev => ({ ...prev, poId, qty: 1 }));
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (event) => {
          const text = event.target?.result as string;
          const lines = text.split('\n').filter(line => line.trim());
          const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

          const partIndex = headers.indexOf('part number');
          const descIndex = headers.indexOf('description');
          const qtyIndex = headers.indexOf('quantity');

          if (partIndex === -1 || qtyIndex === -1) {
              alert("Invalid CSV format. Header must contain 'Part Number' and 'Quantity'.");
              return;
          }

          const itemsToUpload = lines.slice(1).map(line => {
              const columns = line.split(',');
              return {
                  partNumber: columns[partIndex]?.trim() || '',
                  description: columns[descIndex]?.trim() || '',
                  quantity: parseInt(columns[qtyIndex]?.trim() || '0', 10)
              };
          }).filter(item => item.partNumber);

          if (itemsToUpload.length > 0) {
              await onBulkStockUpload(itemsToUpload);
              alert(`Successfully uploaded ${itemsToUpload.length} part records.`);
          }
      };
      reader.readAsText(file);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (activeModal === 'registerPart') {
        await onRegisterPart(formState.partNumber, formState.description, formState.qty);
    } else if (selectedPart) {
        if (activeModal === 'inward') {
            await onInward(selectedPart, formState.qty, formState.remark);
        } else if (activeModal === 'walking') {
            await onWalkingSale(selectedPart, formState.qty, formState.remark);
        } else if (activeModal === 'allocate') {
            await onAllocate(formState.poId, selectedPart, formState.qty);
        }
    }
    closeModal();
  };

  const closeModal = () => {
    setActiveModal(null);
    setFormState({ qty: 1, remark: '', poId: '', partNumber: '', description: '' });
    setPoSearchQuery('');
    setSelectedPart(null);
  };

  return (
    <div className="container mx-auto p-4 sm:p-6 lg:p-8 space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 dark:text-white">Inventory Control</h2>
          <p className="text-slate-500 dark:text-slate-400">Physical stock tracking, inward entries, and PO allocations.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            {onNavigateToReports && (
                <button 
                    onClick={onNavigateToReports}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-200 rounded-lg hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors shadow-sm text-sm font-semibold border border-slate-300 dark:border-slate-600"
                >
                    <ClipboardDocumentListIcon className="w-5 h-5" /> Allocation Report
                </button>
            )}
            <button 
                onClick={() => setActiveModal('registerPart')}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm text-sm font-semibold"
            >
                <PlusIcon className="w-5 h-5" /> Register New Part
            </button>
            <button 
                onClick={downloadStockTemplate}
                className="flex items-center gap-2 px-4 py-2 bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-slate-200 rounded-lg hover:bg-slate-300 dark:hover:bg-slate-600 transition-colors shadow-sm text-sm font-semibold"
            >
                <ArrowDownTrayIcon className="w-5 h-5" /> Template
            </button>
            <label className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 cursor-pointer shadow-sm text-sm font-semibold">
                <ArrowUpTrayIcon className="w-5 h-5" />
                Bulk Inward CSV
                <input type="file" className="hidden" accept=".csv" onChange={handleFileUpload} />
            </label>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-md border border-slate-200 dark:border-slate-700">
        <div className="relative mb-6">
          <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
          <input
            type="text"
            placeholder="Search parts inventory..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-3 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500 outline-none shadow-sm"
          />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase font-bold tracking-wider">
              <tr>
                <th className="p-4 border-b dark:border-slate-700">Part Info</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Physical Total</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Allocated</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Net Available</th>
                <th className="p-4 border-b dark:border-slate-700 text-center">Quick Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y dark:divide-slate-700">
              {filteredStock.map(item => {
                const total = Number(item.totalQuantity || 0);
                const allocated = Number(item.allocatedQuantity || 0);
                const available = total - allocated;
                return (
                  <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors group">
                    <td className="p-4">
                      <p className="font-bold text-slate-900 dark:text-white text-base">{item.partNumber || 'Unknown'}</p>
                      <p className="text-slate-500 dark:text-slate-400 text-xs truncate max-w-xs">{item.description || 'No description'}</p>
                    </td>
                    <td className="p-4 text-right font-medium text-lg">{total}</td>
                    <td className="p-4 text-right text-red-500 font-medium">-{allocated}</td>
                    <td className="p-4 text-right">
                      <span className={`font-black text-xl ${available > 0 ? 'text-green-600 dark:text-green-400' : 'text-slate-400'}`}>
                          {available}
                      </span>
                    </td>
                    <td className="p-4">
                      <div className="flex justify-center gap-1">
                          <button 
                              onClick={() => { setSelectedPart(item.partNumber); setActiveModal('inward'); }}
                              className="p-2 text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20 rounded-lg"
                              title='Inward Stock'
                          >
                              <PlusIcon className="w-5 h-5" />
                          </button>
                          <button 
                               onClick={() => { setSelectedPart(item.partNumber); setActiveModal('walking'); }}
                               className="p-2 text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg"
                               title='Walking Sale'
                          >
                              <CurrencyRupeeIcon className="w-5 h-5" />
                          </button>
                          <button 
                               onClick={() => { setSelectedPart(item.partNumber); setActiveModal('allocate'); }}
                               className="p-2 text-amber-600 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-lg"
                               title='Allocate to PO'
                          >
                              <TruckIcon className="w-5 h-5" />
                          </button>
                          <button 
                               onClick={() => { setSelectedPart(item.partNumber); setActiveModal('history'); }}
                               className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"
                               title='History'
                          >
                              <ClockIcon className="w-5 h-5" />
                          </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredStock.length === 0 && (
            <div className="p-12 text-center text-slate-500 italic">No inventory records found.</div>
          )}
        </div>
      </div>

      {/* Stock Adjust Modal (Combined for Inward, Walking, Allocation, Register) */}
      {activeModal && activeModal !== 'history' && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border dark:border-slate-700">
            <div className="flex justify-between items-center p-6 border-b dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white capitalize">
                {activeModal === 'registerPart' ? 'Register New Part Number' : `${activeModal.replace('_', ' ')} Stock: ${selectedPart}`}
              </h3>
              <button onClick={closeModal}><XMarkIcon className="w-6 h-6" /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-5">
              {activeModal === 'registerPart' && (
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Part Number</label>
                        <input 
                            type="text"
                            required
                            placeholder="e.g., VALV-5W30-1L"
                            className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={formState.partNumber}
                            onChange={e => setFormState({ ...formState, partNumber: e.target.value.toUpperCase() })}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Part Description</label>
                        <textarea 
                            required
                            placeholder="Briefly describe the part..."
                            className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={formState.description}
                            onChange={e => setFormState({ ...formState, description: e.target.value })}
                        />
                    </div>
                </div>
              )}

              {activeModal === 'allocate' && (
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Quick Find PO</label>
                    <div className="relative">
                      <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                      <input 
                        type="text"
                        placeholder="Type PO# or Customer to filter list..."
                        className="w-full pl-9 pr-3 py-2 rounded-lg border dark:bg-slate-900 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-amber-500 outline-none shadow-inner"
                        value={poSearchQuery}
                        onChange={e => setPoSearchQuery(e.target.value)}
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Select Target Purchase Order</label>
                    <select 
                        required
                        className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-amber-500"
                        value={formState.poId}
                        onChange={handlePOSelectionChange}
                    >
                        <option value="">{targetPOsForPart.length > 0 ? "Choose PO needing this part" : "No pending POs need this part"}</option>
                        {targetPOsForPart.map(po => {
                            const item = po.items.find(i => (i.partNumber || '').trim().toLowerCase() === selectedPart?.trim().toLowerCase());
                            const needed = item ? (Number(item.quantity || 0) - Number(item.allocatedQuantity || 0)) : 0;
                            return (
                                <option key={po.id} value={po.id}>
                                    #{po.poNumber} - {po.customerName} (Needs: {needed})
                                </option>
                            );
                        })}
                    </select>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-1">
                    <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Quantity</label>
                    <input 
                        type="number"
                        min="0"
                        required
                        className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-red-500"
                        value={formState.qty}
                        onChange={e => setFormState({ ...formState, qty: Number(e.target.value) })}
                    />
                </div>
                <div className="col-span-1 flex items-end">
                    <p className="text-xs text-slate-500 dark:text-slate-400 pb-2">
                        {activeModal === 'allocate' ? 'Quantity to assign to PO' : activeModal === 'registerPart' ? 'Starting physical units' : 'Physical units to move'}
                    </p>
                </div>
              </div>

              {activeModal !== 'registerPart' && (
                <div>
                  <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Remarks / Reference</label>
                  <textarea 
                      className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-red-500 shadow-inner"
                      placeholder={activeModal === 'inward' ? 'e.g., Supplier Invoice #991' : activeModal === 'allocate' ? 'Reason for specific allocation' : 'e.g., Walk-in customer cash sale'}
                      value={formState.remark}
                      rows={2}
                      onChange={e => setFormState({ ...formState, remark: e.target.value })}
                  />
                </div>
              )}

              <div className="pt-4 flex justify-end gap-3">
                <button type="button" onClick={closeModal} className="px-5 py-2.5 text-slate-500 font-bold hover:text-slate-700 transition-colors">Cancel</button>
                <button type="submit" className={`px-8 py-2.5 rounded-lg font-bold text-white shadow-lg transition-transform active:scale-95 ${activeModal === 'inward' ? 'bg-green-600' : activeModal === 'allocate' ? 'bg-amber-600' : activeModal === 'registerPart' ? 'bg-indigo-600' : 'bg-blue-600'}`}>
                    {activeModal === 'registerPart' ? 'Register Part' : `Confirm ${activeModal}`}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* History Modal */}
      {activeModal === 'history' && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden border dark:border-slate-700">
            <div className="flex justify-between items-center p-6 border-b dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
               <div className="flex items-center gap-2">
                 <ClipboardDocumentListIcon className="w-6 h-6 text-slate-500" />
                 <h3 className="text-xl font-bold text-slate-800 dark:text-white">Movement Log: {selectedPart}</h3>
               </div>
               <button onClick={closeModal}><XMarkIcon className="w-6 h-6" /></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto">
                <div className="space-y-4">
                    {partHistory.length > 0 ? partHistory.map(m => (
                        <div key={m.id} className="flex items-start gap-4 p-4 rounded-xl border dark:border-slate-700 bg-slate-50 dark:bg-slate-900/30">
                            <div className={`p-2 rounded-full flex-shrink-0 ${
                                m.type === 'INWARD' ? 'bg-green-100 text-green-600' : 
                                m.type === 'OUTWARD_WALKING' ? 'bg-blue-100 text-blue-600' : 
                                'bg-amber-100 text-amber-600'
                            }`}>
                                {m.type === 'INWARD' ? <PlusIcon className="w-5 h-5" /> : m.type === 'OUTWARD_WALKING' ? <CurrencyRupeeIcon className="w-5 h-5" /> : <TruckIcon className="w-5 h-5" />}
                            </div>
                            <div className="flex-1">
                                <div className="flex justify-between">
                                    <p className="font-bold text-slate-800 dark:text-white capitalize">{m.type.replace('_', ' ').toLowerCase()}</p>
                                    <p className="text-xs text-slate-500">{new Date(m.timestamp).toLocaleString()}</p>
                                </div>
                                <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">{m.remarks}</p>
                                <p className="text-base font-black mt-2">
                                    {m.type === 'INWARD' ? '+' : '-'} {m.quantity} Units
                                </p>
                            </div>
                        </div>
                    )) : (
                        <div className="text-center py-10 text-slate-500 italic">No movements recorded yet.</div>
                    )}
                </div>
            </div>
            <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-t dark:border-slate-700 flex justify-end">
                <button onClick={closeModal} className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold">Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StockManagementPane;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import POModal from './components/POModal';
import ProcurementSuggestionModal from './components/ProcurementSuggestionModal';
import Sidebar from './components/Sidebar';
import UploadPane from './components/UploadPane';
import AnalysisPane from './components/AnalysisPane';
import ConfirmationModal from './components/ConfirmationModal';
import AllOrdersPane from './components/AllOrdersPane';
import DataManagementPane from './components/DataManagementPane';
import ReportsPane from './components/ReportsPane';
import StockManagementPane from './components/StockManagementPane';
import ErrorBanner from './components/ErrorBanner';
import useLocalStorage from './hooks/useLocalStorage';
import { db, auth } from './services/firebase';
import { collection, onSnapshot, addDoc, doc, updateDoc, writeBatch, query, where, getDocs, serverTimestamp, Timestamp, orderBy, setDoc } from 'firebase/firestore';
import { signInAnonymously } from 'firebase/auth';

import { getProcurementSuggestion } from './services/geminiService';

import type { PurchaseOrder, Notification, LogEntry, POItem, ProcurementSuggestion, StockItem, StockMovement } from './types';
import { POItemStatus, OverallPOStatus, OrderStatus, FulfillmentStatus } from './types';

type ModalType = 'none' | 'poDetail' | 'suggestion';
type Pane = 'dashboard' | 'upload' | 'analysis' | 'allOrders' | 'dataManagement' | 'reports' | 'stockManagement';
type Theme = 'light' | 'dark';

function App() {
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [stock, setStock] = useState<StockItem[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [activeModal, setActiveModal] = useState<ModalType>('none');
  const [activePane, setActivePane] = useState<Pane>('dashboard');
  const [theme, setTheme] = useLocalStorage<Theme>('theme', 'light');

  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);

  const [ordersFilter, setOrdersFilter] = useState<{
      status?: OverallPOStatus;
      fulfillmentStatus?: FulfillmentStatus;
  } | null>(null);

  const [suggestionItem, setSuggestionItem] = useState<POItem | null>(null);
  const [suggestion, setSuggestion] = useState<ProcurementSuggestion | null>(null);
  const [suggestionLoading, setSuggestionLoading] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    status: '',
    customer: '',
    date: '',
    mainBranch: '',
    subBranch: '',
  });

  const [firestoreError, setFirestoreError] = useState<string | null>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
  }, [theme]);

  useEffect(() => {
    signInAnonymously(auth).catch(err => {
        console.warn("Auth check failed:", err.message);
    });

    const handleError = (error: any) => {
        if (error.code === 'permission-denied') {
            setFirestoreError('Database permission denied. Authentication required.');
        }
    };

    const unsubPO = onSnapshot(query(collection(db, "purchaseOrders"), orderBy("createdAt", "desc")), (snapshot) => {
        const pos = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as PurchaseOrder));
        setPurchaseOrders(pos);
    }, handleError);

    const unsubStock = onSnapshot(collection(db, "stock"), (snapshot) => {
        const stocks = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockItem));
        setStock(stocks);
    }, handleError);

    const unsubMovements = onSnapshot(query(collection(db, "stockMovements"), orderBy("timestamp", "desc")), (snapshot) => {
        const mvts = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockMovement));
        setStockMovements(mvts);
    }, handleError);

    const unsubLogs = onSnapshot(query(collection(db, "logs"), orderBy("timestamp", "desc")), (snapshot) => {
        const logsData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as LogEntry));
        setLogs(logsData);
    }, handleError);

    const unsubNotifs = onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc")), (snapshot) => {
        const notifs = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Notification));
        setNotifications(notifs);
    }, handleError);

    return () => {
        unsubPO(); unsubStock(); unsubMovements(); unsubLogs(); unsubNotifs();
    };
}, [theme]);

  const addLog = async (poId: string, action: string) => {
    await addDoc(collection(db, "logs"), { poId, action, timestamp: serverTimestamp() });
  };

  const logStockMovement = async (mvt: Omit<StockMovement, 'id' | 'timestamp'>) => {
    await addDoc(collection(db, "stockMovements"), { ...mvt, timestamp: serverTimestamp() });
  };

  const handleUpdatePO = useCallback(async (updatedPO: PurchaseOrder) => {
    const poRef = doc(db, "purchaseOrders", updatedPO.id);
    await updateDoc(poRef, { ...updatedPO });
    addLog(updatedPO.id, "PO updated.");
  }, []);

  const handleRegisterPart = async (partNumber: string, description: string, initialQty: number) => {
      const stockRef = doc(db, "stock", partNumber);
      await setDoc(stockRef, {
          partNumber,
          description,
          totalQuantity: initialQty,
          allocatedQuantity: 0,
          updatedAt: serverTimestamp()
      }, { merge: true });

      if (initialQty > 0) {
          await logStockMovement({
              partNumber,
              type: 'INWARD',
              quantity: initialQty,
              remarks: 'Initial stock registration'
          });
      }
  };

  const handleBulkStockUpload = async (items: { partNumber: string; description: string; quantity: number }[]) => {
      const batch = writeBatch(db);
      for (const item of items) {
          const stockRef = doc(db, "stock", item.partNumber);
          batch.set(stockRef, {
              partNumber: item.partNumber,
              description: item.description,
              totalQuantity: item.quantity,
              allocatedQuantity: 0,
              updatedAt: serverTimestamp()
          }, { merge: true });
      }
      await batch.commit();

      for (const item of items) {
          if (item.quantity > 0) {
              await logStockMovement({
                  partNumber,
                  type: 'INWARD',
                  quantity: item.quantity,
                  remarks: 'Bulk inward upload'
              });
          }
      }
  };

  const handleInwardStock = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    const newTotal = (existing?.totalQuantity || 0) + qty;

    await setDoc(stockRef, {
        partNumber,
        description: existing?.description || 'Inward Entry',
        totalQuantity: newTotal,
        allocatedQuantity: existing?.allocatedQuantity || 0,
        updatedAt: serverTimestamp()
    }, { merge: true });

    await logStockMovement({
        partNumber,
        type: 'INWARD',
        quantity: qty,
        remarks: `Inward: ${remark}`
    });
  };

  const handleWalkingSale = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    if (!existing || (existing.totalQuantity - existing.allocatedQuantity) < qty) {
        alert("Insufficient available stock for walking sale.");
        return;
    }

    const newTotal = existing.totalQuantity - qty;
    await updateDoc(stockRef, { totalQuantity: newTotal, updatedAt: serverTimestamp() });

    await logStockMovement({
        partNumber,
        type: 'OUTWARD_WALKING',
        quantity: qty,
        remarks: `Walking Sale: ${remark}`
    });
  };

  const handleAllocateStock = async (poId: string, partNumber: string, qty: number) => {
    const targetPo = purchaseOrders.find(p => p.id === poId);
    const targetStock = stock.find(s => s.partNumber === partNumber);

    if (!targetPo || !targetStock) return;
    if ((targetStock.totalQuantity - targetStock.allocatedQuantity) < qty) {
        alert("Insufficient physical stock to allocate.");
        return;
    }

    const batch = writeBatch(db);

    const newItems = targetPo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: (item.allocatedQuantity || 0) + qty };
        }
        return item;
    });

    batch.update(doc(db, "purchaseOrders", poId), { items: newItems });
    batch.update(doc(db, "stock", partNumber), { 
        allocatedQuantity: (targetStock.allocatedQuantity || 0) + qty,
        updatedAt: serverTimestamp()
    });

    await batch.commit();
    await logStockMovement({
        partNumber,
        type: 'ALLOCATION',
        quantity: qty,
        referenceId: poId,
        remarks: `Allocated to PO #${targetPo.poNumber}`
    });
    addLog(poId, `Allocated ${qty} units of ${partNumber} from stock.`);
  };

  const handleSelectPO = useCallback((po: PurchaseOrder) => {
    setSelectedPO(po);
    setActiveModal('poDetail');
  }, []);

  const handleCloseModal = useCallback(() => {
    setActiveModal('none');
    setSelectedPO(null);
  }, []);

  const handleDashboardCardClick = useCallback((type: string) => {
    if (type === 'OPEN') setOrdersFilter({ status: OverallPOStatus.Open });
    else if (type === 'FULLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Fulfillment });
    else if (type === 'PARTIALLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Partial });
    else if (type === 'NOT_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.NotAvailable });
    setActivePane('allOrders');
  }, []);

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-gray-900 text-slate-900 dark:text-slate-100 overflow-hidden">
       {firestoreError && <ErrorBanner projectId="maniranjan-po" message={firestoreError} onDismiss={() => setFirestoreError(null)} />}
      <Sidebar activePane={activePane} setActivePane={setActivePane} />
       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    movements={stockMovements}
                    onInward={handleInwardStock}
                    onWalkingSale={handleWalkingSale}
                    onAllocate={handleAllocateStock}
                    onRegisterPart={handleRegisterPart}
                    onBulkStockUpload={handleBulkStockUpload}
                    onNavigateToReports={() => setActivePane('reports')}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={() => {}} onBulkUpload={() => {}} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} stock={stock} stockMovements={stockMovements} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
        />
       )}
    </div>
  );
}

