       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    movements={stockMovements}
                    onInward={handleInwardStock}
                    onWalkingSale={handleWalkingSale}
                    onAllocate={handleAllocateStock}
                    onRegisterPart={handleRegisterPart}
                    onBulkStockUpload={handleBulkStockUpload}
                    onNavigateToReports={() => setActivePane('reports')}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={() => {}} onBulkUpload={() => {}} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} stock={stock} stockMovements={stockMovements} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
          onGetSuggestion={handleGetSuggestion}
          onUpdateItemStatus={handleUpdateItemStatus}
        />
       )}

       <ProcurementSuggestionModal 
          isOpen={activeModal === 'suggestion'}
          onClose={() => setActiveModal('none')}
          item={suggestionItem}
          suggestion={suggestion}
          isLoading={suggestionLoading}
          error={suggestionError}
       />
    </div>
  );
}

export default App;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import POModal from './components/POModal';
import ProcurementSuggestionModal from './components/ProcurementSuggestionModal';
import Sidebar from './components/Sidebar';
import UploadPane from './components/UploadPane';
import AnalysisPane from './components/AnalysisPane';
import ConfirmationModal from './components/ConfirmationModal';
import AllOrdersPane from './components/AllOrdersPane';
import DataManagementPane from './components/DataManagementPane';
import ReportsPane from './components/ReportsPane';
import StockManagementPane from './components/StockManagementPane';
import ErrorBanner from './components/ErrorBanner';
import useLocalStorage from './hooks/useLocalStorage';
import { db, auth } from './services/firebase';
import { collection, onSnapshot, addDoc, doc, updateDoc, writeBatch, query, where, getDocs, serverTimestamp, Timestamp, orderBy, setDoc } from 'firebase/firestore';
import { signInAnonymously } from 'firebase/auth';

import { getProcurementSuggestion } from './services/geminiService';

import type { PurchaseOrder, Notification, LogEntry, POItem, ProcurementSuggestion, StockItem, StockMovement } from './types';
import { POItemStatus, OverallPOStatus, OrderStatus, FulfillmentStatus } from './types';

type ModalType = 'none' | 'poDetail' | 'suggestion';
type Pane = 'dashboard' | 'upload' | 'analysis' | 'allOrders' | 'dataManagement' | 'reports' | 'stockManagement';
type Theme = 'light' | 'dark';

function App() {
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [stock, setStock] = useState<StockItem[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [activeModal, setActiveModal] = useState<ModalType>('none');
  const [activePane, setActivePane] = useState<Pane>('dashboard');
  const [theme, setTheme] = useLocalStorage<Theme>('theme', 'light');

  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);

  const [ordersFilter, setOrdersFilter] = useState<{
      status?: OverallPOStatus;
      fulfillmentStatus?: FulfillmentStatus;
  } | null>(null);

  const [suggestionItem, setSuggestionItem] = useState<POItem | null>(null);
  const [suggestion, setSuggestion] = useState<ProcurementSuggestion | null>(null);
  const [suggestionLoading, setSuggestionLoading] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    status: '',
    customer: '',
    date: '',
    mainBranch: '',
    subBranch: '',
  });

  const [firestoreError, setFirestoreError] = useState<string | null>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
  }, [theme]);

  useEffect(() => {
    signInAnonymously(auth).catch(err => {
        console.warn("Auth check failed:", err.message);
    });

    const handleError = (error: any) => {
        if (error.code === 'permission-denied') {
            setFirestoreError('Database permission denied. Authentication required.');
        }
    };

    const unsubPO = onSnapshot(query(collection(db, "purchaseOrders"), orderBy("createdAt", "desc")), (snapshot) => {
        const pos = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as PurchaseOrder));
        setPurchaseOrders(pos);
    }, handleError);

    const unsubStock = onSnapshot(collection(db, "stock"), (snapshot) => {
        const stocks = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockItem));
        setStock(stocks);
    }, handleError);

    const unsubMovements = onSnapshot(query(collection(db, "stockMovements"), orderBy("timestamp", "desc")), (snapshot) => {
        const mvts = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockMovement));
        setStockMovements(mvts);
    }, handleError);

    const unsubLogs = onSnapshot(query(collection(db, "logs"), orderBy("timestamp", "desc")), (snapshot) => {
        const logsData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as LogEntry));
        setLogs(logsData);
    }, handleError);

    const unsubNotifs = onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc")), (snapshot) => {
        const notifs = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Notification));
        setNotifications(notifs);
    }, handleError);

    return () => {
        unsubPO(); unsubStock(); unsubMovements(); unsubLogs(); unsubNotifs();
    };
}, [theme]);

  const addLog = async (poId: string, action: string) => {
    await addDoc(collection(db, "logs"), { poId, action, timestamp: serverTimestamp() });
  };

  const logStockMovement = async (mvt: Omit<StockMovement, 'id' | 'timestamp'>) => {
    await addDoc(collection(db, "stockMovements"), { ...mvt, timestamp: serverTimestamp() });
  };

  const handleUpdatePO = useCallback(async (updatedPO: PurchaseOrder) => {
    const poRef = doc(db, "purchaseOrders", updatedPO.id);
    await updateDoc(poRef, { ...updatedPO });
    addLog(updatedPO.id, "PO updated.");
  }, []);

  const handleRegisterPart = async (partNumber: string, description: string, initialQty: number) => {
      const stockRef = doc(db, "stock", partNumber);
      await setDoc(stockRef, {
          partNumber: partNumber,
          description: description,
          totalQuantity: initialQty,
          allocatedQuantity: 0,
          updatedAt: serverTimestamp()
      }, { merge: true });

      if (initialQty > 0) {
          await logStockMovement({
              partNumber: partNumber,
              type: 'INWARD',
              quantity: initialQty,
              remarks: 'Initial stock registration'
          });
      }
  };

  const handleBulkStockUpload = async (items: { partNumber: string; description: string; quantity: number }[]) => {
      const batch = writeBatch(db);
      for (const item of items) {
          const stockRef = doc(db, "stock", item.partNumber);
          batch.set(stockRef, {
              partNumber: item.partNumber,
              description: item.description,
              totalQuantity: item.quantity,
              allocatedQuantity: 0,
              updatedAt: serverTimestamp()
          }, { merge: true });
      }
      await batch.commit();

      for (const item of items) {
          if (item.quantity > 0) {
              await logStockMovement({
                  partNumber: item.partNumber,
                  type: 'INWARD',
                  quantity: item.quantity,
                  remarks: 'Bulk inward upload'
              });
          }
      }
  };

  const handleInwardStock = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    const newTotal = (existing?.totalQuantity || 0) + qty;

    await setDoc(stockRef, {
        partNumber: partNumber,
        description: existing?.description || 'Inward Entry',
        totalQuantity: newTotal,
        allocatedQuantity: existing?.allocatedQuantity || 0,
        updatedAt: serverTimestamp()
    }, { merge: true });

    await logStockMovement({
        partNumber: partNumber,
        type: 'INWARD',
        quantity: qty,
        remarks: `Inward: ${remark}`
    });
  };

  const handleWalkingSale = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    if (!existing || (existing.totalQuantity - existing.allocatedQuantity) < qty) {
        alert("Insufficient available stock for walking sale.");
        return;
    }

    const newTotal = existing.totalQuantity - qty;
    await updateDoc(stockRef, { totalQuantity: newTotal, updatedAt: serverTimestamp() });

    await logStockMovement({
        partNumber: partNumber,
        type: 'OUTWARD_WALKING',
        quantity: qty,
        remarks: `Walking Sale: ${remark}`
    });
  };

  const handleAllocateStock = async (poId: string, partNumber: string, qty: number) => {
    const targetPo = purchaseOrders.find(p => p.id === poId);
    const targetStock = stock.find(s => s.partNumber === partNumber);

    if (!targetPo || !targetStock) return;
    if ((targetStock.totalQuantity - targetStock.allocatedQuantity) < qty) {
        alert("Insufficient physical stock to allocate.");
        return;
    }

    const batch = writeBatch(db);

    const newItems = targetPo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: (item.allocatedQuantity || 0) + qty };
        }
        return item;
    });

    batch.update(doc(db, "purchaseOrders", poId), { items: newItems });
    batch.update(doc(db, "stock", partNumber), { 
        allocatedQuantity: (targetStock.allocatedQuantity || 0) + qty,
        updatedAt: serverTimestamp()
    });

    await batch.commit();
    await logStockMovement({
        partNumber: partNumber,
        type: 'ALLOCATION',
        quantity: qty,
        referenceId: poId,
        remarks: `Allocated to PO #${targetPo.poNumber}`
    });
    addLog(poId, `Allocated ${qty} units of ${partNumber} from stock.`);
  };

  const handleGetSuggestion = async (item: POItem) => {
    setSuggestionLoading(true);
    setSuggestionError(null);
    setSuggestionItem(item);
    setActiveModal('suggestion');
    try {
      const result = await getProcurementSuggestion(item);
      setSuggestion(result);
    } catch (err) {
      setSuggestionError("Failed to fetch procurement strategy from Gemini.");
    } finally {
      setSuggestionLoading(false);
    }
  };

  const handleUpdateItemStatus = async (poId: string, partNumber: string, status: POItemStatus) => {
      const targetPO = purchaseOrders.find(po => po.id === poId);
      if (!targetPO) return;

      const newItems = targetPO.items.map(item => {
          if (item.partNumber === partNumber) {
              return { ...item, status };
          }
          return item;
      });

      await handleUpdatePO({ ...targetPO, items: newItems });
      addLog(poId, `Status for item ${partNumber} updated to ${status}.`);
  };

  const handleSaveSingleOrder = async (order: any) => {
      try {
          const poData = {
              poNumber: order.poNo,
              salesOrderNumber: order.soNo,
              poDate: order.poDate,
              customerName: order.accountName,
              mainBranch: order.mainBranch,
              subBranch: order.subBranch,
              items: order.items.map((i: any) => ({
                  ...i,
                  status: i.stockStatus === 'Available' ? POItemStatus.Available : POItemStatus.NotAvailable
              })),
              saleType: order.saleType,
              creditTerms: order.creditTerms,
              status: OverallPOStatus.Open,
              fulfillmentStatus: order.fulfillmentStatus === 'Fully Available' ? FulfillmentStatus.Fulfillment : FulfillmentStatus.Partial,
              orderStatus: order.orderStatus,
              billingAddress: order.billingAddress,
              billToGSTIN: order.billToGSTIN,
              shippingAddress: order.shippingAddress,
              shipToGSTIN: order.shipToGSTIN,
              quoteNumber: order.quoteNumber,
              pfAvailable: order.pfAvailable,
              checklist: order.checklist,
              checklistRemarks: order.checklistRemarks,
              createdAt: new Date().toISOString(),
              paymentStatus: order.saleType === 'Cash' ? 'Pending' : null,
              paymentNotes: '',
          };
          await addDoc(collection(db, "purchaseOrders"), poData);
          alert("Order saved successfully.");
      } catch (e) {
          console.error("Error saving order:", e);
          alert("Error saving order.");
      }
  };

  const handleBulkUpload = async (parsedOrders: any[]) => {
      const batch = writeBatch(db);
      try {
          for (const order of parsedOrders) {
              const newRef = doc(collection(db, "purchaseOrders"));
              batch.set(newRef, {
                  ...order,
                  createdAt: new Date().toISOString(),
                  paymentNotes: '',
              });
          }
          await batch.commit();
          alert(`Successfully uploaded ${parsedOrders.length} orders.`);
          setActivePane('dashboard');
      } catch (e) {
          console.error("Bulk upload batch error:", e);
          alert("Failed to process bulk upload.");
      }
  };

  const handleSelectPO = useCallback((po: PurchaseOrder) => {
    setSelectedPO(po);
    setActiveModal('poDetail');
  }, []);

  const handleCloseModal = useCallback(() => {
    setActiveModal('none');
    setSelectedPO(null);
    setSuggestionItem(null);
    setSuggestion(null);
  }, []);

  const handleDashboardCardClick = useCallback((type: string) => {
    if (type === 'OPEN') setOrdersFilter({ status: OverallPOStatus.Open });
    else if (type === 'FULLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Fulfillment });
    else if (type === 'PARTIALLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Partial });
    else if (type === 'NOT_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.NotAvailable });
    setActivePane('allOrders');
  }, []);

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-gray-900 text-slate-900 dark:text-slate-100 overflow-hidden">
       {firestoreError && <ErrorBanner projectId="ethen-power-po" message={firestoreError} onDismiss={() => setFirestoreError(null)} />}
      <Sidebar activePane={activePane} setActivePane={setActivePane} />
       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    movements={stockMovements}
                    onInward={handleInwardStock}
                    onWalkingSale={handleWalkingSale}
                    onAllocate={handleAllocateStock}
                    onRegisterPart={handleRegisterPart}
                    onBulkStockUpload={handleBulkStockUpload}
                    onNavigateToReports={() => setActivePane('reports')}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={handleSaveSingleOrder} onBulkUpload={handleBulkUpload} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} stock={stock} stockMovements={stockMovements} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
          onGetSuggestion={handleGetSuggestion}
          onUpdateItemStatus={handleUpdateItemStatus}
        />
       )}

       <ProcurementSuggestionModal 
          isOpen={activeModal === 'suggestion'}
          onClose={() => setActiveModal('none')}
          item={suggestionItem}
          suggestion={suggestion}
          isLoading={suggestionLoading}
          error={suggestionError}
       />
    </div>
  );
}

export default App;

import React, { useState, useCallback } from 'react';
import { ArrowUpTrayIcon, DocumentPlusIcon, PlusIcon, XMarkIcon, ArrowDownTrayIcon } from './icons';
import { MAIN_BRANCHES, BRANCH_STRUCTURE } from '../constants';
import { downloadTemplate } from '../utils/export';
import { OrderStatus, OverallPOStatus, FulfillmentStatus, POItemStatus } from '../types';

interface UploadPaneProps {
    onSaveSingleOrder: (order: any) => void;
    onBulkUpload: (orders: any[]) => void;
}

const initialItemState = { 
    partNumber: '', 
    itemDesc: '', 
    quantity: 1, 
    rate: 0, 
    discount: 0, 
    gst: 18,
    stockAvailable: 0,
    stockInHand: 0,
    allocatedQuantity: 0,
    deliveryQuantity: 0,
    invoicedQuantity: 0,
    stockStatus: 'Available' as 'Available' | 'Unavailable',
    oaDate: '',
    oaNo: '',
    itemType: '',
};

const initialOrderState = {
    mainBranch: '',
    subBranch: '',
    accountName: '',
    poNo: '',
    poDate: new Date().toISOString().split('T')[0],
    soNo: '',
    soDate: new Date().toISOString().split('T')[0],
    items: [initialItemState],
    orderStatus: OrderStatus.OpenOrders,
    fulfillmentStatus: 'Fully Available',
    saleType: 'Credit' as 'Cash' | 'Credit',
    creditTerms: 30,
    pfAvailable: false,
    checklist: {
        bCheck: false,
        cCheck: false,
        dCheck: false,
        battery: false,
        spares: false,
        bd: false,
        radiatorDescaling: false,
        others: false,
    },
    checklistRemarks: '',
    billingAddress: '',
    billToGSTIN: '',
    shippingAddress: '',
    shipToGSTIN: '',
    quoteNumber: '',
};

const UploadPane: React.FC<UploadPaneProps> = ({ onSaveSingleOrder, onBulkUpload }) => {
    const [dragging, setDragging] = useState(false);
    const [order, setOrder] = useState(initialOrderState);

    const parseCSVAndUpload = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            const lines = text.split('\n').filter(l => l.trim());
            if (lines.length < 2) return;

            const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
            const rows = lines.slice(1).map(line => {
                const values: string[] = [];
                let current = '';
                let inQuotes = false;
                for (let char of line) {
                    if (char === '"') inQuotes = !inQuotes;
                    else if (char === ',' && !inQuotes) {
                        values.push(current.trim());
                        current = '';
                    } else current += char;
                }
                values.push(current.trim());
                return values;
            });

            // Map header indices
            const idx = (name: string) => headers.findIndex(h => h.includes(name.toLowerCase()));

            const branchIdx = idx('branch');
            const soNoIdx = idx('sale order number');
            const dateIdx = idx('dates');
            const accountIdx = idx('account name');
            const zoneIdx = idx('zone');
            const poStatIdx = idx('po status');
            const partIdx = idx('item part number');
            const descIdx = idx('item description');
            const qtyIdx = idx('quantity');
            const priceIdx = idx('unit price');
            const discountIdx = idx('discount');
            const gstIdx = idx('tax amount'); // Simple approximation if gst % isn't explicit
            const billIdx = idx('billing address');
            const shipIdx = idx('shipping address');
            const billGstIdx = idx('bill to gstin');
            const shipGstIdx = idx('ship to gstin');
            const quoteIdx = idx('quote number');
            const pfIdx = idx('p & f');
            const matStatIdx = idx('material status');
            const billStatIdx = idx('billing status');

            // Group rows by Sale Order Number
            const poGroups: Record<string, any[]> = {};
            rows.forEach(row => {
                const soNo = row[soNoIdx] || 'UNKNOWN';
                if (!poGroups[soNo]) poGroups[soNo] = [];
                poGroups[soNo].push(row);
            });

            const parsedPOs = Object.values(poGroups).map(group => {
                const first = group[0];

                // Fuzzy status mapping to match dashboard logic
                let status = OverallPOStatus.Open;
                const rawStat = (first[poStatIdx] || '').toLowerCase();
                if (rawStat.includes('cancel')) status = OverallPOStatus.Cancelled;
                if (rawStat.includes('fulfill') || rawStat.includes('done')) status = OverallPOStatus.Fulfilled;

                let fulfillment = FulfillmentStatus.Partial;
                const rawFill = (first[billStatIdx] || '').toLowerCase();
                if (rawFill.includes('fully') || rawFill.includes('fulfillment')) fulfillment = FulfillmentStatus.Fulfillment;
                if (rawFill.includes('not')) fulfillment = FulfillmentStatus.NotAvailable;

                const items = group.map(row => ({
                    partNumber: row[partIdx] || 'N/A',
                    itemDesc: row[descIdx] || '',
                    quantity: parseFloat(row[qtyIdx]) || 0,
                    rate: parseFloat(row[priceIdx]) || 0,
                    discount: parseFloat(row[discountIdx]) || 0,
                    gst: 18, // Default fallback
                    status: (row[matStatIdx] || '').toLowerCase().includes('avail') ? POItemStatus.Available : POItemStatus.NotAvailable,
                    allocatedQuantity: 0,
                    deliveryQuantity: 0,
                    invoicedQuantity: 0,
                }));

                return {
                    poNumber: first[soNoIdx] || 'N/A', // Mapping SO to PO# for demo context
                    salesOrderNumber: first[soNoIdx] || 'N/A',
                    poDate: first[dateIdx] || new Date().toISOString().split('T')[0],
                    customerName: first[accountIdx] || 'Unknown Customer',
                    mainBranch: first[branchIdx] || '',
                    subBranch: first[zoneIdx] || '',
                    items,
                    status,
                    fulfillmentStatus: fulfillment,
                    orderStatus: OrderStatus.OpenOrders,
                    saleType: 'Credit',
                    creditTerms: 30,
                    billingAddress: first[billIdx] || '',
                    billToGSTIN: first[billGstIdx] || '',
                    shippingAddress: first[shipIdx] || '',
                    shipToGSTIN: first[shipGstIdx] || '',
                    quoteNumber: first[quoteIdx] || '',
                    pfAvailable: (first[pfIdx] || '').toLowerCase() === 'true',
                    checklist: {
                        bCheck: false, cCheck: false, dCheck: false, battery: false,
                        spares: false, bd: false, radiatorDescaling: false, others: false,
                    }
                };
            });

            onBulkUpload(parsedPOs);
        };
        reader.readAsText(file);
    };

    const handleOrderChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const isCheckbox = type === 'checkbox';
        const checkedValue = (e.target as HTMLInputElement).checked;

        if (name === 'mainBranch') {
            setOrder(prev => ({ ...prev, mainBranch: value, subBranch: '' }));
        } else {
            setOrder(prev => ({ ...prev, [name]: isCheckbox ? checkedValue : value }));
        }
    };

    const handleSaleTypeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const saleType = e.target.value as 'Cash' | 'Credit';
        setOrder(prev => ({
            ...prev,
            saleType,
            creditTerms: saleType === 'Credit' ? 30 : 0,
        }));
    };

    const handleChecklistChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, checked } = e.target;
        setOrder(prev => ({
            ...prev,
            checklist: { ...prev.checklist, [name]: checked }
        }));
    };

    const handleItemChange = (index: number, e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setOrder(prev => {
            const newItems = prev.items.map((item, i) => {
                if (i === index) {
                    return { ...item, [name]: value };
                }
                return item;
            });
            return { ...prev, items: newItems };
        });
    };

    const addItem = () => {
        setOrder(prev => ({ ...prev, items: [...prev.items, { ...initialItemState }] }));
    };

    const removeItem = (index: number) => {
        setOrder(prev => ({ ...prev, items: prev.items.filter((_, i) => i !== index) }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSaveSingleOrder(order);
        setOrder(initialOrderState);
    };

    const totals = React.useMemo(() => {
        return order.items.reduce((acc, item) => {
            const qty = Number(item.quantity) || 0;
            const rate = Number(item.rate) || 0;
            const discount = Number(item.discount) || 0;
            const gst = Number(item.gst) || 0;

            const unitExt = qty * rate;
            const netTaxable = unitExt - discount;
            const gstAmount = netTaxable * (gst / 100);
            const total = netTaxable + gstAmount;

            acc.grossValue += unitExt;
            acc.totalDiscount += discount;
            acc.netTaxableValue += netTaxable;
            acc.gst += gstAmount;
            acc.totalAmount += total;

            return acc;
        }, { grossValue: 0, totalDiscount: 0, netTaxableValue: 0, gst: 0, totalAmount: 0 });
    }, [order.items]);

    const handleDragEnter = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault(); e.stopPropagation(); setDragging(true);
    };

    const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault(); e.stopPropagation(); setDragging(false);
    };

    const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault(); e.stopPropagation();
    };

    const handleDrop = useCallback((e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        e.stopPropagation();
        setDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files[0]) {
            parseCSVAndUpload(e.dataTransfer.files[0]);
        }
    }, [onBulkUpload]);

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            parseCSVAndUpload(e.target.files[0]);
        }
    };

    const renderField = (label: string, name: string, type = 'text', options?: {value: string, label: string}[], required = false) => {
        const commonProps = {
            id: name,
            name,
            required,
            className: "mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500",
            onChange: handleOrderChange,
        };

        return (
            <div>
                <label htmlFor={name} className="block text-sm font-medium text-slate-700 dark:text-slate-300">{label}</label>
                {type === 'select' ? (
                    <select {...commonProps} value={(order as any)[name]}>
                        {options?.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                    </select>
                ) : (
                    <input type={type} {...commonProps} value={(order as any)[name]} />
                )}
            </div>
        );
    }

    return (
        <div className="container mx-auto p-4 sm:p-6 lg:p-8">
            <div className="grid grid-cols-1 gap-8">
                <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg space-y-4">
                    <h2 className="text-2xl font-semibold mb-2 flex items-center gap-3">
                        <DocumentPlusIcon className="w-7 h-7 text-red-500" />
                        <span>Manual Sales Order Entry</span>
                    </h2>
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg">
                            <h3 className="md:col-span-2 text-lg font-medium text-slate-800 dark:text-white -mb-2">Document Details</h3>
                            {renderField("PO No.", "poNo", "text", [], true)}
                            {renderField("PO Date", "poDate", "date", [], true)}
                            {renderField("SO No.", "soNo", "text", [], true)}
                            {renderField("SO Date", "soDate", "date", [], true)}
                            {renderField("Quote Number", "quoteNumber", "text", [], false)}

                            <h3 className="md:col-span-2 text-lg font-medium text-slate-800 dark:text-white pt-4 mt-2 border-t dark:border-slate-700 -mb-2">Customer & Branch</h3>
                            <div className="md:col-span-2">
                                {renderField("Account Name", "accountName", "text", [], true)}
                            </div>
                            <div>
                                <label htmlFor="mainBranch" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Main Branch</label>
                                <select id="mainBranch" name="mainBranch" value={order.mainBranch} onChange={handleOrderChange} required className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500">
                                    <option value="">Select Main Branch</option>
                                    {MAIN_BRANCHES.map(b => <option key={b} value={b}>{b}</option>)}
                                </select>
                            </div>
                            <div>
                                <label htmlFor="subBranch" className="block text-sm font-medium text-slate-700 dark:text-slate-300">Sub Branch</label>
                                <select id="subBranch" name="subBranch" value={order.subBranch} onChange={handleOrderChange} required disabled={!order.mainBranch} className="mt-1 block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500 disabled:opacity-50">
                                    <option value="">Select Sub Branch</option>
                                    {order.mainBranch && BRANCH_STRUCTURE[order.mainBranch]?.map(sb => <option key={sb} value={sb}>{sb}</option>)}
                                </select>
                            </div>

                            <h3 className="md:col-span-2 text-lg font-medium text-slate-800 dark:text-white pt-4 mt-2 border-t dark:border-slate-700 -mb-2">Addresses</h3>
                            {renderField("Billing Address", "billingAddress", "text", [], false)}
