const convertToCSV = (data: PurchaseOrder[]): string => {
    const headers = [
        'Main Branch',
        'Sub Branch',
        'Account Name',
        'PO No.',
        'PO Date',
        'SO No.',
        'SO Date',
        'Quote Number',
        'Billing Address',
        'Bill To GSTIN',
        'Shipping Address',
        'Ship To GSTIN',
        'Sale Type',
        'Credit Terms',
        'Order Status',
        'Fulfillment Status',
        'P & F Available',
        'B-Check',
        'C-Check',
        'D-Check',
        'Battery',
        'Spares',
        'BD',
        'Radiator Descaling',
        'Others',
        'Checklist Remarks',
        'Item Name',
        'Item Type',
        'Item Description',
        'Qty',
        'Unit Price',
        'Discount Amt',
        'GST %',
        'Stock Status',
        'OA No.',
        'OA Date'
    ];

    const rows: string[] = [];

    const safe = (str: any) => {
        if (str === undefined || str === null) return '""';
        const s = String(str).replace(/"/g, '""');
        return `"${s}"`;
    };

    data.forEach(po => {
        const checklist = po.checklist || {
            bCheck: false,
            cCheck: false,
            dCheck: false,
            battery: false,
            spares: false,
            bd: false,
            radiatorDescaling: false,
            others: false,
        };
        const items = po.items && po.items.length > 0 ? po.items : [{} as any];

        items.forEach(item => {
            const row = [
                safe(po.mainBranch),
                safe(po.subBranch),
                safe(po.customerName),
                safe(po.poNumber),
                safe(po.poDate),
                safe(po.salesOrderNumber),
                safe(po.soDate),
                safe(po.quoteNumber),
                safe(po.billingAddress),
                safe(po.billToGSTIN),
                safe(po.shippingAddress),
                safe(po.shipToGSTIN),
                safe(po.saleType),
                safe(po.creditTerms),
                safe(po.orderStatus),
                safe(po.fulfillmentStatus),
                safe(po.pfAvailable ? 'TRUE' : 'FALSE'),
                safe(checklist.bCheck ? 'TRUE' : 'FALSE'),
                safe(checklist.cCheck ? 'TRUE' : 'FALSE'),
                safe(checklist.dCheck ? 'TRUE' : 'FALSE'),
                safe(checklist.battery ? 'TRUE' : 'FALSE'),
                safe(checklist.spares ? 'TRUE' : 'FALSE'),
                safe(checklist.bd ? 'TRUE' : 'FALSE'),
                safe(checklist.radiatorDescaling ? 'TRUE' : 'FALSE'),
                safe(checklist.others ? 'TRUE' : 'FALSE'),
                safe(po.checklistRemarks),
                safe(item.partNumber),
                safe(item.itemType),
                safe(item.itemDesc),
                safe(item.quantity),
                safe(item.rate),
                safe(item.discount),
                safe(item.gst),
                safe(item.status),
                safe(item.oaNo),
                safe(item.oaDate)
            ];
            rows.push(row.join(','));
        });
    });

    return [headers.join(','), ...rows].join('\n');
};

export const exportToCSV = (data: PurchaseOrder[], filename: string = 'purchase_orders_detailed.csv'): void => {
    const csvString = convertToCSV(data);
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    if (link.download !== undefined) {
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }
};

