  partNumber: string;
  type: 'INWARD' | 'OUTWARD_WALKING' | 'ALLOCATION' | 'TRANSFER' | 'DEALLOCATION';
  quantity: number;
  referenceId?: string;
  remarks: string;
  timestamp: string;
}

export interface QuotationItem {
