type Theme = 'light' | 'dark';

/**
 * Strict data sanitizer. 
 * Ensures state only contains serializable JSON-friendly data.
 * Prevents internal Firestore/Firebase objects from causing circular reference errors.
 */
const sanitizeData = (data: any): any => {
    // Handle primitives immediately
    if (data === null || typeof data !== 'object') {
        return data;
    }

    // Handle Firestore Timestamp
    if (data instanceof Timestamp || (data && typeof data.toDate === 'function')) {
        try {
            return data.toDate().toISOString();
        } catch {
            return String(data);
        }
    }

    // Handle Firestore DocumentReference / CollectionReference
    // These contain references to the Firestore instance ('db'), which is circular.
    if (data && data.path && typeof data.path === 'string' && (data._firestore || data.firestore)) {
        return data.path;
    }

    // Handle Arrays
    if (Array.isArray(data)) {
        return data.map(sanitizeData);
    }

    // Handle Plain Objects
    // Only recurse if it's a plain object to avoid walking class instances (Firestore, Auth, etc.)
    if (Object.getPrototypeOf(data) === Object.prototype || data.constructor.name === 'Object') {
        const sanitized: any = {};
        for (const key in data) {
            if (Object.prototype.hasOwnProperty.call(data, key)) {
                sanitized[key] = sanitizeData(data[key]);
            }
        }
        return sanitized;
    }

    // Fallback for unknown complex objects: convert to string to break circularity
    return String(data);
};

function App() {
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [stock, setStock] = useState<StockItem[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [activeModal, setActiveModal] = useState<ModalType>('none');
  const [activePane, setActivePane] = useState<Pane>('dashboard');
  const [theme, setTheme] = useLocalStorage<Theme>('theme', 'light');

  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);

  const [ordersFilter, setOrdersFilter] = useState<{
      status?: OverallPOStatus;
      fulfillmentStatus?: FulfillmentStatus;
  } | null>(null);

  const [suggestionItem, setSuggestionItem] = useState<POItem | null>(null);
  const [suggestion, setSuggestion] = useState<ProcurementSuggestion | null>(null);
  const [suggestionLoading, setSuggestionLoading] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    status: '',
    customer: '',
    date: '',
    mainBranch: '',
    subBranch: '',
  });

  const [firestoreError, setFirestoreError] = useState<string | null>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
  }, [theme]);

  useEffect(() => {
    signInAnonymously(auth).catch(err => {
        console.warn("Auth check failed:", err.message);
    });

    const handleError = (error: any) => {
        if (error.code === 'permission-denied') {
            setFirestoreError('Database permission denied. Authentication required.');
        }
    };

    const unsubPO = onSnapshot(query(collection(db, "purchaseOrders"), orderBy("createdAt", "desc")), (snapshot) => {
        const pos = snapshot.docs.map(doc => sanitizeData({ ...doc.data(), id: doc.id }) as PurchaseOrder);
        setPurchaseOrders(pos);
    }, handleError);

    const unsubStock = onSnapshot(collection(db, "stock"), (snapshot) => {
        const stocks = snapshot.docs.map(doc => sanitizeData({ ...doc.data(), id: doc.id }) as StockItem);
        setStock(stocks);
    }, handleError);

    const unsubMovements = onSnapshot(query(collection(db, "stockMovements"), orderBy("timestamp", "desc")), (snapshot) => {
        const mvts = snapshot.docs.map(doc => sanitizeData({ ...doc.data(), id: doc.id }) as StockMovement);
        setStockMovements(mvts);
    }, handleError);

    const unsubLogs = onSnapshot(query(collection(db, "logs"), orderBy("timestamp", "desc")), (snapshot) => {
        const logsData = snapshot.docs.map(doc => sanitizeData({ ...doc.data(), id: doc.id }) as LogEntry);
        setLogs(logsData);
    }, handleError);

    const unsubNotifs = onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc")), (snapshot) => {
        const notifs = snapshot.docs.map(doc => sanitizeData({ ...doc.data(), id: doc.id }) as Notification);
        setNotifications(notifs);
    }, handleError);

    return () => {
        unsubPO(); unsubStock(); unsubMovements(); unsubLogs(); unsubNotifs();
    };
}, [theme]);

  const addLog = async (poId: string, action: string) => {
    await addDoc(collection(db, "logs"), { poId, action, timestamp: serverTimestamp() });
  };

  const logStockMovement = async (mvt: Omit<StockMovement, 'id' | 'timestamp'>) => {
    await addDoc(collection(db, "stockMovements"), { ...mvt, timestamp: serverTimestamp() });
  };

  const handleUpdatePO = useCallback(async (updatedPO: PurchaseOrder) => {
    // Sanitize data before sending to Firestore just in case
    const cleanPO = sanitizeData(updatedPO);
    const poRef = doc(db, "purchaseOrders", cleanPO.id);
    await updateDoc(poRef, { ...cleanPO });
    addLog(cleanPO.id, "PO updated.");
  }, []);

  const handleRegisterPart = async (partNumber: string, description: string, initialQty: number) => {
      const stockRef = doc(db, "stock", partNumber);
      await setDoc(stockRef, {
          partNumber: partNumber,
          description: description,
          totalQuantity: initialQty,
          allocatedQuantity: 0,
          updatedAt: serverTimestamp()
      }, { merge: true });

      if (initialQty > 0) {
          await logStockMovement({
              partNumber: partNumber,
              type: 'INWARD',
              quantity: initialQty,
              remarks: 'Initial stock registration'
          });
      }
  };

  const handleBulkStockUpload = async (items: { partNumber: string; description: string; quantity: number }[]) => {
      const batch = writeBatch(db);
      for (const item of items) {
          const stockRef = doc(db, "stock", item.partNumber);
          batch.set(stockRef, {
              partNumber: item.partNumber,
              description: item.description,
              totalQuantity: item.quantity,
              allocatedQuantity: 0,
              updatedAt: serverTimestamp()
          }, { merge: true });
      }
      await batch.commit();

      for (const item of items) {
          if (item.quantity > 0) {
              await logStockMovement({
                  partNumber: item.partNumber,
                  type: 'INWARD',
                  quantity: item.quantity,
                  remarks: 'Bulk inward upload'
              });
          }
      }
  };

  const handleInwardStock = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    const newTotal = (existing?.totalQuantity || 0) + qty;

    await setDoc(stockRef, {
        partNumber: partNumber,
        description: existing?.description || 'Inward Entry',
        totalQuantity: newTotal,
        allocatedQuantity: existing?.allocatedQuantity || 0,
        updatedAt: serverTimestamp()
    }, { merge: true });

    await logStockMovement({
        partNumber: partNumber,
        type: 'INWARD',
        quantity: qty,
        remarks: `Inward: ${remark}`
    });
  };

  const handleWalkingSale = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    if (!existing || (existing.totalQuantity - existing.allocatedQuantity) < qty) {
        alert("Insufficient available stock for walking sale.");
        return;
    }

    const newTotal = existing.totalQuantity - qty;
    await updateDoc(stockRef, { totalQuantity: newTotal, updatedAt: serverTimestamp() });

    await logStockMovement({
        partNumber: partNumber,
        type: 'OUTWARD_WALKING',
        quantity: qty,
        remarks: `Walking Sale: ${remark}`
    });
  };

  const handleAllocateStock = async (poId: string, partNumber: string, qty: number) => {
    const targetPo = purchaseOrders.find(p => p.id === poId);
    const targetStock = stock.find(s => s.partNumber === partNumber);

    if (!targetPo || !targetStock) return;
    if ((targetStock.totalQuantity - targetStock.allocatedQuantity) < qty) {
        alert("Insufficient physical stock to allocate.");
        return;
    }

    const batch = writeBatch(db);

    const newItems = targetPo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: (item.allocatedQuantity || 0) + qty };
        }
        return item;
    });

    batch.update(doc(db, "purchaseOrders", poId), { items: newItems });
    batch.update(doc(db, "stock", partNumber), { 
        allocatedQuantity: (targetStock.allocatedQuantity || 0) + qty,
        updatedAt: serverTimestamp()
    });

    await batch.commit();
    await logStockMovement({
        partNumber: partNumber,
        type: 'ALLOCATION',
        quantity: qty,
        referenceId: poId,
        remarks: `Allocated to PO #${targetPo.poNumber}`
    });
    addLog(poId, `Allocated ${qty} units of ${partNumber} from stock.`);
  };

  const handleGetSuggestion = async (item: POItem) => {
    setSuggestionLoading(true);
    setSuggestionError(null);
    setSuggestionItem(item);
    setActiveModal('suggestion');
    try {
      const result = await getProcurementSuggestion(item);
      setSuggestion(result);
    } catch (err) {
      setSuggestionError("Failed to fetch procurement strategy from Gemini.");
    } finally {
      setSuggestionLoading(false);
    }
  };

  const handleUpdateItemStatus = async (poId: string, partNumber: string, status: POItemStatus) => {
      const targetPO = purchaseOrders.find(po => po.id === poId);
      if (!targetPO) return;

      const newItems = targetPO.items.map(item => {
          if (item.partNumber === partNumber) {
              return { ...item, status };
          }
          return item;
      });

      await handleUpdatePO({ ...targetPO, items: newItems });
      addLog(poId, `Status for item ${partNumber} updated to ${status}.`);
  };

  const handleSaveSingleOrder = async (order: any) => {
      try {
          const poData = sanitizeData({
              poNumber: order.poNo,
              salesOrderNumber: order.soNo,
              poDate: order.poDate,
              customerName: order.accountName,
              mainBranch: order.mainBranch,
              subBranch: order.subBranch,
              items: order.items.map((i: any) => ({
                  ...i,
                  status: i.stockStatus === 'Available' ? POItemStatus.Available : POItemStatus.NotAvailable
              })),
              saleType: order.saleType,
              creditTerms: order.creditTerms,
              // Fix: Replaced OverallPOStatus.Open with OverallPOStatus.Available as default
              status: OverallPOStatus.Available,
              fulfillmentStatus: order.fulfillmentStatus === 'Fully Available' ? FulfillmentStatus.Fulfillment : FulfillmentStatus.Partial,
              orderStatus: order.orderStatus,
              billingAddress: order.billingAddress,
              billToGSTIN: order.billToGSTIN,
              shippingAddress: order.shippingAddress,
              shipToGSTIN: order.shipToGSTIN,
              quoteNumber: order.quoteNumber,
              pfAvailable: order.pfAvailable,
              checklist: order.checklist,
              checklistRemarks: order.checklistRemarks,
              createdAt: new Date().toISOString(),
              paymentStatus: order.saleType === 'Cash' ? 'Pending' : null,
              paymentNotes: '',
          });
          await addDoc(collection(db, "purchaseOrders"), poData);
          alert("Order saved successfully.");
      } catch (e) {
          console.error("Error saving order:", e);
          alert("Error saving order.");
      }
  };

  const handleBulkUpload = async (parsedOrders: any[]) => {
      const batch = writeBatch(db);
      try {
          for (const order of parsedOrders) {
              const newRef = doc(collection(db, "purchaseOrders"));
              batch.set(newRef, sanitizeData({
                  ...order,
                  createdAt: new Date().toISOString(),
                  paymentNotes: '',
              }));
          }
          await batch.commit();
          alert(`Successfully uploaded ${parsedOrders.length} orders.`);
          setActivePane('dashboard');
      } catch (e) {
          console.error("Bulk upload batch error:", e);
          alert("Failed to process bulk upload.");
      }
  };

  const handleSelectPO = useCallback((po: PurchaseOrder) => {
    setSelectedPO(po);
    setActiveModal('poDetail');
  }, []);

  const handleCloseModal = useCallback(() => {
    setActiveModal('none');
    setSelectedPO(null);
    setSuggestionItem(null);
    setSuggestion(null);
  }, []);

  const handleDashboardCardClick = useCallback((type: string) => {
    // Fix: OverallPOStatus.Open was removed; 'OPEN' dashboard card now displays all active orders by clearing the status filter.
    if (type === 'OPEN') setOrdersFilter(null);
    else if (type === 'FULLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Fulfillment });
    else if (type === 'PARTIALLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Partial });
    else if (type === 'NOT_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.NotAvailable });
    setActivePane('allOrders');
  }, []);

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-gray-900 text-slate-900 dark:text-slate-100 overflow-hidden">
       {firestoreError && <ErrorBanner projectId="ethenpo-3afb3" message={firestoreError} onDismiss={() => setFirestoreError(null)} />}
      <Sidebar activePane={activePane} setActivePane={setActivePane} />
       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    movements={stockMovements}
                    onInward={handleInwardStock}
                    onWalkingSale={handleWalkingSale}
                    onAllocate={handleAllocateStock}
                    onRegisterPart={handleRegisterPart}
                    onBulkStockUpload={handleBulkStockUpload}
                    onNavigateToReports={() => setActivePane('reports')}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={handleSaveSingleOrder} onBulkUpload={handleBulkUpload} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} stock={stock} stockMovements={stockMovements} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
          onGetSuggestion={handleGetSuggestion}
          onUpdateItemStatus={handleUpdateItemStatus}
        />
       )}

       <ProcurementSuggestionModal 
          isOpen={activeModal === 'suggestion'}
          onClose={() => setActiveModal('none')}
          item={suggestionItem}
          suggestion={suggestion}
          isLoading={suggestionLoading}
          error={suggestionError}
       />
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import type { PurchaseOrder, OverallPOStatus, FulfillmentStatus, POItem } from '../types';
import { POItemStatus } from '../types';
import { MagnifyingGlassIcon, ArrowDownTrayIcon, TrashIcon, XMarkIcon } from './icons';
import { exportToCSV } from '../utils/export';

interface AllOrdersPaneProps {
  purchaseOrders: PurchaseOrder[];
  onSelectPO: (po: PurchaseOrder) => void;
  onDeletePO: (poId: string) => void;
  filter?: { status?: OverallPOStatus, fulfillmentStatus?: FulfillmentStatus } | null;
  onClearFilter?: () => void;
}

type SortKeys = 'poNumber' | 'customerName' | 'poDate' | 'totalValue' | 'status' | 'fulfillmentStatus' | 'orderStatus';

const AllOrdersPane: React.FC<AllOrdersPaneProps> = ({ purchaseOrders, onSelectPO, onDeletePO, filter, onClearFilter }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: SortKeys; direction: 'ascending' | 'descending' } | null>({ key: 'poDate', direction: 'descending' });

    const posWithValues = useMemo(() => {
        return purchaseOrders.map(po => ({
            ...po,
            totalValue: (po.items || []).reduce((acc, item) => {
                const val = Number(item.quantity || 0) * Number(item.rate || 0);
                return acc + (isNaN(val) ? 0 : val);
            }, 0)
        }));
    }, [purchaseOrders]);

    const filteredAndSortedPOs = useMemo(() => {
        let sortableItems = [...posWithValues];

        // Apply external filter
        if (filter) {
            if (filter.status) {
                // Fix: Removed reference to 'Open' and 'Partially Dispatched' as they are not in OverallPOStatus enum
                sortableItems = sortableItems.filter(po => po.status === filter.status);
            }
            if (filter.fulfillmentStatus) {
                sortableItems = sortableItems.filter(po => po.fulfillmentStatus === filter.fulfillmentStatus);
            }
        }

        if (searchTerm) {
            sortableItems = sortableItems.filter(po =>
                (po.poNumber || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
                (po.customerName || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
                (po.mainBranch || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
                (po.subBranch || '').toLowerCase().includes(searchTerm.toLowerCase())
            );
        }

        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                const valA = a[sortConfig.key] || '';
                const valB = b[sortConfig.key] || '';
                if (valA < valB) {
                    return sortConfig.direction === 'ascending' ? -1 : 1;
                }
                if (valA > valB) {
                    return sortConfig.direction === 'ascending' ? 1 : -1;
                }
                return 0;
            });
        }
        return sortableItems;
    }, [posWithValues, searchTerm, sortConfig, filter]);

    const requestSort = (key: SortKeys) => {
        let direction: 'ascending' | 'descending' = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const getSortIndicator = (key: SortKeys) => {
        if (!sortConfig || sortConfig.key !== key) return null;
        return sortConfig.direction === 'ascending' ? '▲' : '▼';
    };

    const getItemStats = (items: POItem[]) => {
        const i = items || [];
        const available = i.filter(i => i.status === POItemStatus.Available || i.status === POItemStatus.Dispatched).length;
        const partial = i.filter(i => i.status === POItemStatus.PartiallyAvailable).length;
        const notAvailable = i.filter(i => i.status === POItemStatus.NotAvailable).length;
        return { available, partial, notAvailable };
    };

    return (
        <div className="container mx-auto p-4 sm:p-6 lg:p-8 h-full flex flex-col">
            <div className="flex flex-col sm:flex-row justify-between items-center mb-4 gap-4">
                <div className="relative w-full sm:w-72">
                    <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input
                        type="text"
                        placeholder="Search orders..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 text-base rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500"
                    />
                </div>
                <div className="flex items-center gap-3">
                    {filter && (
                         <div className="flex items-center gap-2 bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-200 px-3 py-1.5 rounded-full text-sm font-medium">
                            <span>Filtering by: {filter.status || filter.fulfillmentStatus}</span>
                            <button onClick={onClearFilter} className="hover:text-red-900 dark:hover:text-white"><XMarkIcon className="w-4 h-4"/></button>
                         </div>
                    )}
                    <button
                        onClick={() => exportToCSV(filteredAndSortedPOs)}
                        className="w-full sm:w-auto flex items-center justify-center gap-2 px-4 py-2.5 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                    >
                        <ArrowDownTrayIcon className="w-5 h-5" />
                        Export to Excel
                    </button>
                </div>
            </div>

            <div className="flex-grow overflow-auto rounded-lg shadow-md border border-slate-200 dark:border-slate-700">
                <table className="w-full text-left text-base text-slate-500 dark:text-slate-400">
                    <thead className="text-sm text-slate-700 dark:text-slate-300 uppercase bg-slate-50 dark:bg-slate-800 sticky top-0 z-10">
                        <tr>
                            <th scope="col" className="p-4 cursor-pointer" onClick={() => requestSort('poNumber')}>PO Number {getSortIndicator('poNumber')}</th>
                            <th scope="col" className="p-4 cursor-pointer" onClick={() => requestSort('customerName')}>Customer {getSortIndicator('customerName')}</th>
                            <th scope="col" className="p-4">Branch</th>
                            <th scope="col" className="p-4 cursor-pointer" onClick={() => requestSort('poDate')}>Date {getSortIndicator('poDate')}</th>
                            <th scope="col" className="p-4 cursor-pointer text-right" onClick={() => requestSort('totalValue')}>Value {getSortIndicator('totalValue')}</th>
                            <th scope="col" className="p-4 cursor-pointer" onClick={() => requestSort('orderStatus')}>Order Status {getSortIndicator('orderStatus')}</th>
                            <th scope="col" className="p-4 w-64">Item Availability (Breakdown)</th>
                            <th scope="col" className="p-4 text-center">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800/50">
                        {filteredAndSortedPOs.map(po => {
                            const stats = getItemStats(po.items);
                            const totalItems = (po.items || []).length;
                            return (
                                <tr key={po.id} className="border-b dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                    <td className="p-4 font-medium text-slate-900 dark:text-white whitespace-nowrap">{po.poNumber}</td>
                                    <td className="p-4">{po.customerName}</td>
                                    <td className="p-4">{po.mainBranch}{po.subBranch && ` / ${po.subBranch}`}</td>
                                    <td className="p-4">{new Date(po.poDate).toLocaleDateString()}</td>
                                    <td className="p-4 text-right font-semibold">{po.totalValue.toLocaleString('en-IN', { style: 'currency', currency: 'INR' })}</td>
                                    <td className="p-4 font-medium">{po.orderStatus}</td>
                                    <td className="p-4">
                                        <div className="flex flex-col gap-1 w-full max-w-[200px]">
                                            <div className="flex text-xs font-semibold text-white overflow-hidden rounded-full h-4 w-full bg-slate-200 dark:bg-slate-700">
                                                {stats.available > 0 && (
                                                    <div className="bg-green-500 flex items-center justify-center" style={{ width: `${(stats.available / totalItems) * 100}%` }} title={`${stats.available} Available`}></div>
                                                )}
                                                {stats.partial > 0 && (
                                                    <div className="bg-yellow-500 flex items-center justify-center" style={{ width: `${(stats.partial / totalItems) * 100}%` }} title={`${stats.partial} Partial`}></div>
                                                )}
                                                {stats.notAvailable > 0 && (
                                                    <div className="bg-red-500 flex items-center justify-center" style={{ width: `${(stats.notAvailable / totalItems) * 100}%` }} title={`${stats.notAvailable} Not Available`}></div>
                                                )}
                                            </div>
                                            <div className="flex justify-between text-xs text-slate-500 dark:text-slate-400 font-medium">
                                                <span className={stats.available > 0 ? "text-green-600 dark:text-green-400" : ""}>{stats.available} Avail</span>
                                                <span className={stats.partial > 0 ? "text-yellow-600 dark:text-yellow-400" : ""}>{stats.partial} Part</span>
                                                <span className={stats.notAvailable > 0 ? "text-red-600 dark:text-red-400" : ""}>{stats.notAvailable} N/A</span>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center items-center gap-2">
                                            <button onClick={() => onSelectPO(po)} className="font-medium text-red-600 dark:text-red-500 hover:underline">Details</button>
                                            <button onClick={() => onDeletePO(po.id)} className="text-red-500 hover:text-red-700 p-1.5 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50">
                                                <TrashIcon className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
                 {filteredAndSortedPOs.length === 0 && (
                    <div className="text-center p-10 text-slate-500 dark:text-slate-400 bg-white dark:bg-slate-800/50">
                        No orders match your criteria.
                    </div>
                )}
            </div>
        </div>
    );
};

export default AllOrdersPane;
